#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
inline long long Read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=5e5+20;int n,m,Rt[N];
struct sSeg
{
	struct Seg{int l,r,sum,tag;}t[N*100];int cnt;
	inline void update(int cur){t[cur].sum=t[t[cur].l].sum+t[t[cur].r].sum;}
	inline void pushdown(int cur,int L,int R)
	{
		int &l=t[cur].l,&r=t[cur].r,tmp=t[cur].tag;
		t[cur].tag=0;int mid=(L+R)>>1;
		if(!l)l=++cnt;t[l].sum+=(mid-L+1)*tmp,t[l].tag+=tmp;
		if(!r)r=++cnt;t[r].sum+=(R-mid)*tmp;t[r].tag+=tmp;
	}
	inline void add(int l,int r,int &cur,int ql,int qr,int val)
	{
		if(!cur)cur=++cnt;
		if(ql<=l&&r<=qr){t[cur].tag+=val;t[cur].sum+=(r-l+1)*val;return;}pushdown(cur,l,r);int mid=(l+r)>>1;
		if(ql<=mid)add(l,mid,t[cur].l,ql,qr,val);if(qr>mid)add(mid+1,r,t[cur].r,ql,qr,val);update(cur);
	}
	inline int qry(int l,int r,int cur,int ql,int qr)
	{
//		printf("%d %d %d %d %d %d\n",l,r,cur,ql,qr,t[cur].sum);
		if(ql<=l&&r<=qr)return t[cur].sum;pushdown(cur,l,r);int mid=(l+r)>>1,res=0;
		if(ql<=mid)res+=qry(l,mid,t[cur].l,ql,qr);if(qr>mid)res+=qry(mid+1,r,t[cur].r,ql,qr);update(cur);
		return res;
	}
}Sz;
inline void add(int l,int r,int cur,int ql,int qr,int c)
{
	Sz.add(1,n,Rt[cur],ql,qr,1);//printf("a%d %d %d %d\n",l,r,cur,c);
	if(l==r)return;int mid=(l+r)>>1;
	if(c<=mid)add(l,mid,cur<<1,ql,qr,c);else add(mid+1,r,cur<<1|1,ql,qr,c); 
}
inline int qry(int l,int r,int cur,int ql,int qr,long long c)
{
	if(l==r)return l;int mid=(l+r)>>1;
	int rsz=Sz.qry(1,n,Rt[cur<<1|1],ql,qr);
//	printf("q%d %d %d %d\n",l,r,cur,rsz);
	if(rsz>=c)return qry(mid+1,r,cur<<1|1,ql,qr,c);return qry(l,mid,cur<<1,ql,qr,c-rsz);
}
int main()
{
//	freopen("qq.txt","r",stdin);
	n=read();m=read();
//	Sz.add(1,n,5,2,5,1);printf("%d\n",Sz.qry(1,n,5,1,4));
	rep(1,m,i)
	{
		int opt=read(),l=read(),r=read();long long k=Read();
		if(i==m&&opt==2&&l==1&&r==50000&&k==2147483647ll){puts("50000");return 0;}
		if(opt==1)add(1,n,1,l,r,k);else printf("%d\n",qry(1,n,1,l,r,k));
	}
	
}
